import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases / edge cases ---
  it.todo("empty item list -> premium 5 G (only processing fee)");
  it.todo("quote with unknown item type -> throws an error");

  // --- Single main item base premiums ---
  it.todo("single plain sword (steel, enchantment 0, not cursed) -> premium 105 G (100 base + 5 fee)");
  it.todo("single plain amulet -> premium 65 G (60 + 5)");
  it.todo("single plain staff -> premium 85 G (80 + 5)");
  it.todo("single plain potion -> premium 45 G (40 + 5)");

  // --- Components: per-piece and building-block pricing ---
  it.todo("2 runes -> premium 55 G (50 base + 5 fee)");
  it.todo("3 runes -> premium 65 G (60 block + 5 fee)");
  it.todo("4 runes -> premium 105 G (100 base, no block + 5 fee)");
  it.todo("7 runes -> premium 180 G (175 + 5)");
  it.todo("2 runes + 1 moonstone -> premium 80 G (75 + 5; no block, different types)");
  it.todo("3 runes + 3 moonstones -> premium 125 G (60 + 60 = 120 + 5; two separate blocks)");

  // --- Premium modifier thresholds ---
  it.todo("cursed sword (50% surcharge) -> premium 155 G (100 + 50 + 5)");
  it.todo("sword with enchantment 5 -> high-enchantment surcharge applies; premium 135 G (100 + 30 + 5)");
  it.todo("sword with enchantment 4 -> no high-enchantment surcharge; premium 105 G");
  it.todo("cursed sword with enchantment 5 -> both surcharges apply; premium 185 G (100 + 50 + 30 + 5)");
  it.todo("customer with exactly 2 years -> loyalty discount applies; sword premium 85 G (100 - 20 + 5)");
  it.todo("customer with 1 year -> no loyalty discount; sword premium 105 G");
  it.todo("first insurance (no previous contract) -> 10% surcharge applied to policy base; sword premium 115 G (100 + 10 + 5)");
  it.todo("follow-up contract (second quote in scenario) -> 15% discount on policy base; sword premium 90 G (100 - 15 + 5)");

  // --- Multi-item policies and modifier scope ---
  it.todo("policy with cursed sword + plain amulet -> premium 215 G (100 + 60 + 50 + 5; curse only on sword's base)");
  it.todo("two swords -> premium 205 G (100 + 100 + 5)");

  // --- Rounding in MHPCO's favor (premium rounded up) ---
  it.todo("premium that yields 197.5 G fractional -> rounded up to 198 G");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (0 years, no prior) -> premium 165 G");
  it.todo("long-standing customer's second contract: cursed sword ench 7 -> premium 160 G");

  // --- Claim processing: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 G -> payout 400 G");
  it.todo("rune (no enchantment/material), damage 200 G -> payout 100 G");

  // --- Claim processing: special clauses ---
  it.todo("high-enchantment (>=8) item: 50% reimbursement then deductible -- dragon sword ench 8 dmg 1000 -> payout 400 G");
  it.todo("dragon-material sword ench 9, damage 1000 G -> payout 400 G (50% rule wins)");
  it.todo("dragon-material sword ench 5, damage 800 G -> payout 700 G (only dragon-material clause)");
  it.todo("steel sword ench 9, damage 1000 G -> payout 400 G (only high-enchantment clause)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) -> total payout 600 G (deductible per item)");

  // --- Multiple items of the same type ---
  it.todo("policy covers two swords -> insurance sum 2000 G, cap 4000 G; two sword damages each gets own deductible");
  it.todo("damages contains more entries of a type than insured -> CLI rejects whole claim (non-zero exit)");

  // --- Cap exhaustion ---
  it.todo("sword (cap 2000 G); two claims of 1500 G -- first payout 1400, second payout 600 (capped); remainingCap 0");
  it.todo("cap is based on unmodified insurance value (cursed sword cap 2000 G)");
  it.todo("sword + 3 runes block -> insurance sum 1750 G (block discount doesn't affect insurance sum)");

  // --- Rounding in MHPCO's favor (payout rounded down) ---
  it.todo("payout that yields 350.5 G fractional -> rounded down to 350 G");

  // --- Claim error cases ---
  it.todo("claim references item not in policy -> CLI rejects (non-zero exit)");
  it.todo("claim damage entry with negative amount -> CLI rejects (non-zero exit)");
});

