input.content:
const KNOWN_TYPES = new Set([
  "sword",
  "amulet",
  "staff",
  "potion",
  "rune",
  "moonstone",
]);

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

const PROCESSING_FEE = 5;

function quotePremium(items: Item[]): number {
  for (const item of items) {
    if (!KNOWN_TYPES.has(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
  return PROCESSING_FEE;
}

export function runScenario(scenario: Scenario): { results: { premium: number }[] } {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
}

