input.newString:
function quotePremium(items: Item[], customer: Customer): number {
  const policyBase = policyBasePremium(items);
  const surcharges = itemSurcharges(items);
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  const loyalty = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
    ? policyBase * LOYALTY_RATE
    : 0;
  const totalBeforeFee = policyBase + surcharges + firstInsurance - loyalty;
  return Math.ceil(totalBeforeFee) + PROCESSING_FEE;
}

export function runScenario(scenario: Scenario): { results: { premium: number }[] } {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items, scenario.customer),
  }));
  return { results };
}

