function rawPayoutForDamage(item: Item, damageAmount: number): number {
  const ench = item.enchantment ?? 0;
  const isDragon = item.material === "dragon";
  let reimbursable = damageAmount;
  if (ench >= 8) {
    reimbursable = damageAmount * 0.5;
  } else if (isDragon) {
    reimbursable = damageAmount;
  }
  // Note: spec says "high-enchantment clause applies, then deductible"
  // even for dragon material when both apply -- 50% wins.
  return reimbursable;
}

